PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE edge_runs (
    run_id INTEGER PRIMARY KEY AUTOINCREMENT,
    session_id TEXT NOT NULL,
    workload_type TEXT NOT NULL,
    workload_size_mb REAL,
    run_number INTEGER NOT NULL,
    timestamp_start TEXT NOT NULL,
    timestamp_end TEXT NOT NULL,
    duration_seconds REAL,
    data_sent_mb REAL,
    scaphandre_joules REAL,
    powerstat_joules REAL,
    cpu_peak_percent REAL,
    cpu_avg_percent REAL,
    powertop_flag TEXT,
    notes TEXT
);
CREATE TABLE edge_baselines (
    baseline_id INTEGER PRIMARY KEY AUTOINCREMENT,
    session_id TEXT NOT NULL,
    timestamp TEXT NOT NULL,
    workload_type TEXT,
    idle_power_scaphandre_w REAL,
    idle_power_powerstat_w REAL,
    idle_cpu_percent REAL,
    baseline_duration_seconds REAL DEFAULT 60,
    baseline_energy_joules REAL,
    dominant_idle_processes TEXT
);
CREATE TABLE cloud_runs (
    run_id INTEGER PRIMARY KEY AUTOINCREMENT,
    session_id TEXT NOT NULL,
    workload_type TEXT NOT NULL,
    workload_size_mb REAL,
    run_number INTEGER NOT NULL,
    timestamp_start TEXT NOT NULL,
    timestamp_end TEXT NOT NULL,
    duration_seconds REAL,
    data_sent_mb REAL,
    bandwidth_out_mb REAL,
    response_time_ms REAL,
    cpu_avg_percent REAL,
    request_count INTEGER,
    notes TEXT
);
CREATE TABLE IF NOT EXISTS "cloud_derived_energy_DO_backup" (
    derivation_id INTEGER PRIMARY KEY AUTOINCREMENT,
    session_id TEXT NOT NULL,
    workload_type TEXT NOT NULL,
    total_bandwidth_gb REAL,
    total_cpu_hours REAL,
    mean_response_time_ms REAL,
    total_requests INTEGER,
    energy_model_used TEXT,
    energy_per_gb_wh REAL,
    pue_factor REAL,
    datacenter_region TEXT,
    estimated_total_energy_joules REAL,
    estimated_energy_per_request_joules REAL,
    estimated_energy_per_gb_joules REAL,
    estimated_cost_usd REAL,
    derivation_notes TEXT,
    timestamp TEXT NOT NULL
);
CREATE TABLE sessions (
    session_id TEXT PRIMARY KEY,
    created_at TEXT NOT NULL,
    workload_type TEXT,
    environment TEXT,
    team_notes TEXT,
    status TEXT DEFAULT 'active'
);
CREATE TABLE cloud_reported_energy (report_id INTEGER PRIMARY KEY AUTOINCREMENT, session_id TEXT NOT NULL, workload_type TEXT NOT NULL, gcp_project_id TEXT NOT NULL, gcp_region TEXT NOT NULL, reporting_period_start TEXT, reporting_period_end TEXT, electricity_kwh REAL, gross_carbon_gco2e REAL, net_carbon_gco2e REAL, pue_actual REAL, renewable_energy_percent REAL, derived_joules REAL, carbon_model_version TEXT, data_source TEXT DEFAULT 'GCP Carbon Footprint API', awaiting_api_data INTEGER DEFAULT 1, timestamp TEXT NOT NULL, attribution_method TEXT, attribution_share_percent REAL, total_project_energy_joules REAL);
CREATE TABLE client_energy_runs (
    run_id INTEGER PRIMARY KEY AUTOINCREMENT,
    session_id TEXT NOT NULL,
    environment TEXT NOT NULL,
    workload_type TEXT NOT NULL,
    workload_size_mb REAL,
    run_number INTEGER NOT NULL,
    timestamp_start TEXT NOT NULL,
    timestamp_end TEXT NOT NULL,
    duration_seconds REAL,
    data_sent_mb REAL,
    client_scaphandre_joules REAL,
    client_powerstat_joules REAL,
    client_cpu_peak_percent REAL,
    client_cpu_avg_percent REAL,
    response_time_ms REAL,
    notes TEXT
  );
CREATE TABLE client_energy_baselines (
    baseline_id INTEGER PRIMARY KEY AUTOINCREMENT,
    session_id TEXT NOT NULL,
    environment TEXT NOT NULL,
    timestamp TEXT NOT NULL,
    workload_type TEXT,
    idle_power_scaphandre_w REAL,
    idle_power_powerstat_w REAL,
    idle_cpu_percent REAL,
    baseline_duration_seconds REAL DEFAULT 60,
    baseline_energy_joules REAL
  );
DELETE FROM sqlite_sequence;
COMMIT;
